  if (typeof v['repo'] !== 'string' || v['repo'].length === 0) {
    return Err(createErrorEnvelope('tool_input_invalid', 'get_callees: repo must be a non-empty string'));
  }
  return Ok({ symbol_qname: v['symbol_qname'], repo: v['repo'] });
}

