get(taskDescription: string, sddPhase: string, domainTags: string[]): SkillsmithCacheEntry | null {
  if (!this.isCacheEnabled()) return null;

  const key = this.getCacheKey(taskDescription, sddPhase, domainTags);
  const entry = this.cache.get(key);
  if (!entry) return null;

  // Check TTL
  if (Date.now() > entry.expires_at) {
    this.cache.delete(key);
    return null;
  }

  // Update access order (LRU)
  const idx = this.accessOrder.indexOf(key);
  if (idx !== -1) {
    this.accessOrder.splice(idx, 1);
  }
  this.accessOrder.push(key);

  return entry;
}

private getCacheKey(taskDescription: string, sddPhase: string, domainTags: string[]): string {
  const sortedTags = (domainTags ?? []).sort().join(',');
  const input = `${taskDescription}|${sddPhase}|${sortedTags}`;
  // Simple hash — we use SHA256 in the spec but a string key works fine for Node.js
  return crypto.subtle ? `hash:${input}` : input;
}

set(
  taskDescription: string,
  sddPhase: string,
  domainTags: string[],
  value: Omit<SkillsmithCacheEntry, 'expires_at'>,
): void {
  if (!this.isCacheEnabled()) return;

  const key = this.getCacheKey(taskDescription, sddPhase, domainTags);

  // Evict oldest if at capacity
  if (this.cache.size >= this.maxEntries && !this.cache.has(key)) {
    const oldest = this.accessOrder.shift();
    if (oldest) this.cache.delete(oldest);
  }

  const entry: SkillsmithCacheEntry = {
    ...value,
    expires_at: Date.now() + this.ttlMs,
  };
  this.cache.set(key, entry);
  const idx = this.accessOrder.indexOf(key);
  if (idx !== -1) {
    this.accessOrder.splice(idx, 1);
  }
  this.accessOrder.push(key);
}

