function readHeader(req: Request, name: string): string | null {
  const v = req.headers[name];
  if (typeof v === 'string' && v.length > 0) return v;
  if (Array.isArray(v) && v.length > 0 && typeof v[0] === 'string') return v[0];
  return null;
}

function verifySignature(
  secret: string,
  rawBody: Buffer,
  header: string,
): boolean {
  // Header format: "sha256=<hex64>"
  if (!header.startsWith('sha256=')) {
    return false;
  }
  const provided = header.slice('sha256='.length);
  if (provided.length === 0) {
    return false;
  }

  const expected = crypto
    .createHmac('sha256', secret)
    .update(rawBody)
    .digest('hex');

  // timingSafeEqual requires equal-length buffers — bail early if the
  // provided hex isn't well-formed (would throw otherwise).
  if (provided.length !== expected.length) {
    return false;
  }

  let providedBuf: Buffer;
  let expectedBuf: Buffer;
  try {
    providedBuf = Buffer.from(provided, 'hex');
    expectedBuf = Buffer.from(expected, 'hex');
  } catch {
    return false;
  }
  if (providedBuf.length !== expectedBuf.length) {
    return false;
  }
  return crypto.timingSafeEqual(providedBuf, expectedBuf);
}

source_snippets.TheForge.src.services.routes.graph.KgLru:
get(key: string): KgLruEntry | undefined {
  const entry = this._cache.get(key);
  if (entry === undefined) return undefined;
  // Refresh recency: re-inserting moves the key to the tail (MRU position).
  this._cache.delete(key);
  this._cache.set(key, entry);
  return entry;
}

set(key: string, entry: KgLruEntry): void {
  if (this._cache.has(key)) this._cache.delete(key);
  this._cache.set(key, entry);
  // Evict the LRU (head) entry when over capacity.
  while (this._cache.size > this._maxEntries) {
    const oldest = this._cache.keys().next().value;
    if (oldest === undefined) break;
    this._cache.delete(oldest);
  }
}

