export async function probeCodeIndexerDetail(
  baseUrl: string,
  service: string,
  preFetchedBody?: unknown,
): Promise<Pick<
  ServiceDiagnostics,
  | 'indexerQueueDepth'
  | 'indexerRunningJobs'
  | 'indexerRepoCount'
  | 'indexerEmbedderBackend'
  | 'indexerEmbedderAvailable'
  | 'indexerEmbedderModel'
  | 'indexerEmbedderDim'
  | 'indexerEmbedderLastError'
> | null> {
  // The primary /health probe already fetched this exact endpoint. Re-use
  // its parsed body when available to save a round-trip; fall back to a
  // fresh fetch only for direct callers.
  const body =
    preFetchedBody !== undefined && preFetchedBody !== null
      ? preFetchedBody
      : await tryFetchJson(`${baseUrl}/health`);
  if (body === null) return null;

  const runningJobs = readNumber(body, 'running_jobs');
  const indexedRepos = readStringArray(body, 'indexed_repos');

  const out: {
    -readonly [K in
      | 'indexerQueueDepth'
      | 'indexerRunningJobs'
      | 'indexerRepoCount'
      | 'indexerEmbedderBackend'
      | 'indexerEmbedderAvailable'
      | 'indexerEmbedderModel'
      | 'indexerEmbedderDim'
      | 'indexerEmbedderLastError']?: ServiceDiagnostics[K];
  } = {};

  if (runningJobs !== null) {
    out.indexerRunningJobs = runningJobs;
    // Code Indexer does not yet expose `queue_depth` separately. We derive
    // a conservative lower bound: anything beyond a single in-flight job is
    // queue pressure. The day the indexer surfaces a real queue depth, this
    // line goes away (BUC follow-up).
    out.indexerQueueDepth = Math.max(0, runningJobs - 1);
    setIndexerRunningJobs(service, runningJobs);
    setIndexerQueueDepth(service, out.indexerQueueDepth);
  }
  if (indexedRepos !== null) {
    out.indexerRepoCount = indexedRepos.length;
  }

  // CIS PR #71 — `/health.embedder` block. Older indexers don't ship this
  // key; in that case we omit ALL embedder fields (graceful degrade) and
  // do not publish the gauge — the previous value would mislead operators
  // more than no value at all.
  const embedder = readObject(body, 'embedder');
  if (embedder !== null) {
    const available = readBoolean(embedder, 'available');
    const backend = coerceEmbedderBackend(
      (embedder as Record<string, unknown>)['backend'],
    );
    const model = readString(embedder, 'model');
    const dim = readNumber(embedder, 'dim');
    const lastError = readString(embedder, 'last_error');

    out.indexerEmbedderBackend = backend;
    if (available !== null) {
      out.indexerEmbedderAvailable = available;
      setIndexerEmbedderAvailable(service, backend, available);
    }
    if (model !== null) out.indexerEmbedderModel = model;
    if (dim !== null) out.indexerEmbedderDim = dim;
    if (lastError !== null) out.indexerEmbedderLastError = lastError;
  }

  return Object.keys(out).length > 0 ? out : null;
}

