function readArray(o: unknown, key: string): readonly unknown[] | null {
  if (o === null || typeof o !== 'object') return null;
  const v = (o as Record<string, unknown>)[key];
  return Array.isArray(v) ? v : null;
}

function readBoolean(o: unknown, key: string): boolean | null {
  if (o === null || typeof o !== 'object') return null;
  const v = (o as Record<string, unknown>)[key];
  return typeof v === 'boolean' ? v : null;
}

function readNumber(o: unknown, key: string): number | null {
  if (o === null || typeof o !== 'object') return null;
  const v = (o as Record<string, unknown>)[key];
  return typeof v === 'number' && Number.isFinite(v) ? v : null;
}

function readObject(o: unknown, key: string): Record<string, unknown> | null {
  if (o === null || typeof o !== 'object') return null;
  const v = (o as Record<string, unknown>)[key];
  return v !== null && typeof v === 'object' && !Array.isArray(v)
    ? (v as Record<string, unknown>)
    : null;
}

function readString(o: unknown, key: string): string | null {
  if (o === null || typeof o !== 'object') return null;
  const v = (o as Record<string, unknown>)[key];
  return typeof v === 'string' && v.length > 0 ? v : null;
}

function readStringArray(o: unknown, key: string): readonly string[] | null {
  const arr = readArray(o, key);
  if (arr === null) return null;
  const out: string[] = [];
  for (const item of arr) {
    if (typeof item === 'string') out.push(item);
  }
  return out;
}

async function tryFetchJson(url: string): Promise<unknown | null> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), DETAIL_PROBE_TIMEOUT_MS);
  try {
    const res = await fetch(url, { signal: controller.signal });
    if (!res.ok) return null;
    return await res.json();
  } catch {
    return null;
  } finally {
    clearTimeout(timer);
  }
}

export function createHealthServicesRouter(): Router {
  const router = createRouter();

  router.get('/', async (_req: Request, res: Response) => {
    if (inflightRequestCount >= MAX_INFLIGHT_REQUESTS) {
      const snapshot =
        lastSnapshot ?? [
          frontendRow(Number(process.env['WEB_PORT'] ?? 3000), new Date().toISOString()),
        ];
      res.setHeader('x-forge-health-cached', '1');
      res.json({ services: snapshot });
      return;
    }

    inflightRequestCount += 1;
    try {
      const probe = await probeAllServices();
      res.json({ services: probe });
    } finally {
      inflightRequestCount -= 1;
    }
  });

  return router;
}

function frontendRow(fePort: number, nowIso: string): ServiceProbeResult {
  return {
    name: 'Frontend',
    port: fePort,
    status: 'healthy',
    latencyMs: null,
    detail: { note: 'Self-reported — the FE renders this page, so it is up.' },
    lastCheckedAt: nowIso,
  };
}

function getState(name: string): SidecarState {
  let s = sidecarState.get(name);
  if (!s) {
    s = {
      cached: null,
      cachedAt: 0,
      inflight: null,
      consecutiveFailures: 0,
      breaker: 'closed',
      breakerOpenedAt: 0,
    };
    sidecarState.set(name, s);
  }
  return s;
}

export async function probeAllServices(): Promise<ServiceProbeResult[]> {
  const bePort = Number(process.env['PORT'] ?? 3001);
  const fePort = Number(process.env['WEB_PORT'] ?? 3000);
  const indexerUrl = (process.env['CODE_INDEXER_URL'] ?? 'http://127.0.0.1:8003').replace(/\/$/, '');
  const skillsmithUrl = (process.env['SKILLSMITH_URL'] ?? 'http://127.0.0.1:47950').replace(/\/$/, '');
  const manifestUrl = (process.env['MANIFEST_URL'] ?? 'http://127.0.0.1:2099').replace(/\/$/, '');
  const manifestKey = process.env['MANIFEST_AGENT_KEY'];
  const manifestConfigured = typeof manifestKey === 'string' && manifestKey.length > 0;

  const nowIso = new Date().toISOString();

  const reRankerUrl = (process.env['RERANKER_URL'] ?? '').replace(/\/$/, '');
  const hhemScorerUrl = (process.env['HHEM_SCORER_URL'] ?? '').replace(/\/$/, '');

  const fePromise: Promise<ServiceProbeResult> = Promise.resolve(frontendRow(fePort, nowIso));

  // TheForge Backend's diagnostics block carries reachability signals for
  // the two ancillary sidecars (TEI rerank, HHEM scorer) — they don't
  // warrant their own status row but operators still need to see them.
  const bePromise = probeSidecar(
    'TheForge Backend',
    bePort,
    `http://127.0.0.1:${bePort}/health`,
    async () => {
      const [tei, hhem] = await Promise.all([
        reRankerUrl.length > 0
          ? probeTeiRerankDetail(reRankerUrl)
          : Promise.resolve(null),
        probeHhemDetail(hhemScorerUrl.length > 0 ? hhemScorerUrl : undefined),
      ]);
      const out: { -readonly [K in keyof ServiceDiagnostics]: ServiceDiagnostics[K] } = {
        ...hhem,
      };
      if (tei !== null) Object.assign(out, tei);
      return Object.keys(out).length > 0 ? (out as ServiceDiagnostics) : null;
    },
  );
  const indexerPromise = probeSidecar(
    'Code Indexer',
    8003,
    `${indexerUrl}/health`,
    (row) => probeCodeIndexerDetail(indexerUrl, 'Code Indexer', row.detail),
  );
  const skillsmithPromise = probeSidecar(
    'Skillsmith',
    47950,
    `${skillsmithUrl}/health`,
    () => probeSkillsmithDetail(skillsmithUrl, 'Skillsmith'),
  );
  const manifestPromise: Promise<ServiceProbeResult> = manifestConfigured
    ? probeSidecar(
        'Manifest Gateway',
        2099,
        `${manifestUrl}/health`,
        (row) => probeManifestDetail(manifestUrl, 'Manifest Gateway', row.detail),
      )
    : Promise.resolve(unconfiguredManifestRow(nowIso));

  const snapshot = await Promise.all([
    bePromise,
    fePromise,
    indexerPromise,
    skillsmithPromise,
    manifestPromise,
  ]);

  lastSnapshot = snapshot;
  return snapshot;
}

export async function probeSidecar(
  name: string,
  port: number,
  url: string,
  enrich?: (row: ServiceProbeResult) => Promise<ServiceDiagnostics | null>,
): Promise<ServiceProbeResult> {
  const state = getState(name);
  const now = Date.now();

  // 1. Fresh cache hit.
  if (state.cached && now - state.cachedAt < PROBE_CACHE_TTL_MS) {
    return state.cached;
  }

  // 2. Circuit breaker OPEN — synthetic unreachable.
  if (state.breaker === 'open') {
    if (now - state.breakerOpenedAt < BREAKER_OPEN_MS) {
      const row: ServiceProbeResult = {
        name,
        port,
        status: 'unreachable',
        latencyMs: null,
        detail: { error: 'circuit_open', breakerOpenedAt: state.breakerOpenedAt },
        lastCheckedAt: new Date(now).toISOString(),
      };
      publishMetric(row);
      return row;
    }
    // Window elapsed — promote to half-open and allow one probe.
    state.breaker = 'half-open';
  }

  // 3. Coalesce concurrent callers onto the single in-flight probe.
  if (state.inflight) {
    return state.inflight;
  }

  // 4. Fire a real probe.
  state.inflight = (async () => {
    try {
      const baseRow = await rawProbeHttp(name, port, url);
      const failed =
        baseRow.status === 'down' || baseRow.status === 'unreachable';

      // Detail-probe enrichment runs only when the primary probe was
      // successful. A failed detail probe MUST NOT downgrade the row to
      // failed; on enrichment error we simply omit `diagnostics`.
      let row: ServiceProbeResult = baseRow;
      if (!failed && enrich) {
        try {
          const diagnostics = await enrich(baseRow);
          if (diagnostics !== null) {
            row = { ...baseRow, diagnostics };
          }
        } catch {
          // Enrichment is best-effort — never alters status.
        }
      }

      if (failed) {
        state.consecutiveFailures += 1;
        if (state.consecutiveFailures >= BREAKER_THRESHOLD) {
          state.breaker = 'open';
          state.breakerOpenedAt = Date.now();
        }
      } else {
        state.consecutiveFailures = 0;
        state.breaker = 'closed';
      }

      state.cached = row;
      state.cachedAt = Date.now();
      publishMetric(row);
      return row;
    } finally {
      state.inflight = null;
    }
  })();

  return state.inflight;
}

function publishMetric(row: ServiceProbeResult): void {
  try {
    setSidecarHealth(row.name, statusToGauge(row.status));
  } catch {
    // Metric publish must never throw — fail-soft.
  }
}

async function rawProbeHttp(
  name: string,
  port: number,
  url: string,
): Promise<ServiceProbeResult> {
  const startedAt = Date.now();
  const lastCheckedAt = new Date().toISOString();
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), PROBE_TIMEOUT_MS);

  try {
    const res = await fetch(url, { signal: controller.signal });
    const latencyMs = Date.now() - startedAt;
    let detail: unknown = null;
    try {
      detail = await res.json();
    } catch {
      detail = { http_status: res.status };
    }

    if (!res.ok) {
      return {
        name,
        port,
        status: res.status >= 500 ? 'down' : 'degraded',
        latencyMs,
        detail,
        lastCheckedAt,
      };
    }

    const upstreamStatus =
      detail !== null &&
      typeof detail === 'object' &&
      typeof (detail as { status?: unknown }).status === 'string'
        ? (detail as { status: string }).status
        : 'ok';

    const normalized: ServiceStatus =
      upstreamStatus === 'degraded' ? 'degraded' : 'healthy';

    return { name, port, status: normalized, latencyMs, detail, lastCheckedAt };
  } catch (error) {
    const latencyMs = Date.now() - startedAt;
    const message =
      error instanceof Error
        ? error.name === 'AbortError'
          ? `Timed out after ${PROBE_TIMEOUT_MS}ms`
          : error.message
        : 'Unknown error';
    return {
      name,
      port,
      status: 'down',
      latencyMs,
      detail: { error: message },
      lastCheckedAt,
    };
  } finally {
    clearTimeout(timer);
  }
}

function unconfiguredManifestRow(nowIso: string): ServiceProbeResult {
  return {
    name: 'Manifest Gateway',
    port: 2099,
    status: 'unconfigured',
    latencyMs: null,
    detail: { note: 'MANIFEST_AGENT_KEY is unset — gateway disabled.' },
    lastCheckedAt: nowIso,
  };
}

