export function createTelemetryRoutes(deps: AppDependencies): Router {
  const router = Router();

  router.post('/deprecated-route', async (req, res) => {
    const body = (req.body ?? {}) as { from?: unknown; to?: unknown };
    const from = typeof body.from === 'string' ? body.from : '';
    const to   = typeof body.to   === 'string' ? body.to   : '';

    if (!from || !to || from.length > MAX_PATH_LEN || to.length > MAX_PATH_LEN) {
      res.status(400).json(createErrorEnvelope('invalid_payload', 'from and to are required string paths (max 256 chars)'));
      return;
    }

    // Only accept /admin/* deprecations — the only window currently open.
    // Reject other prefixes so this surface stays purpose-built and easy
    // to grep when we close the window.
    if (!from.startsWith('/admin/')) {
      res.status(400).json(createErrorEnvelope('unsupported_path', 'Only /admin/* deprecations are accepted'));
      return;
    }

    const trail = deps.auditTrailAsync;
    if (!trail) {
      // Fail-open — telemetry is non-fatal. Return 204 so the SPA never
      // surfaces an error to the user mid-redirect.
      res.status(204).end();
      return;
    }

    const actorId = (req as { actor?: { id?: string } }).actor?.id ?? null;
    try {
      await trail.record(auditWebDeprecatedRoute({ from, to, actorId }));
      res.status(204).end();
    } catch {
      // Fail-open. The deprecation grep query simply sees fewer events;
      // we never block the user's redirect on telemetry write failure.
      res.status(204).end();
    }
  });

  return router;
}

